// import-shopify-data — Assemble, Write, and Checkpoint
// Merges all Shopify API responses into shopify-import.json.
// Writes the artifact atomically. Updates the checkpoint.
//
// Input items (4 items from parallel HTTP Request nodes):
//   item[0]: Fetch Shop Basics response
//   item[1]: Fetch Active Products response
//   item[2]: Fetch Custom Collections response
//   item[3]: Fetch Smart Collections response
//
// The orchestrator passes runtime_config + project context via the trigger.
// We retrieve it from the Subworkflow Trigger output stored by n8n.

const fs   = require('fs');
const path = require('path');

// Retrieve runtime context from Subworkflow Trigger output
// n8n makes previous node outputs available via $node["Node Name"].json
const triggerData   = $node['Subworkflow Trigger'].json;
const runtimeConfig = triggerData.runtime_config;
const projectId     = triggerData.project_id;

if (!runtimeConfig || !projectId) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config and project_id are required');
}

const projectRoot = runtimeConfig.project_root;

// ── Parse API responses ───────────────────────────────────────────────────
const allItems = $input.all();

const shopResponse         = allItems[0].json;
const productsResponse     = allItems[1].json;
const customColResponse    = allItems[2].json;
const smartColResponse     = allItems[3].json;

const rawShopData = shopResponse.shop || {};
const rawProducts = productsResponse.products || [];

// Merge custom and smart collections, tagging each with type
const customCollections = (customColResponse.custom_collections || []).map((c) => ({ ...c, type: 'custom' }));
const smartCollections  = (smartColResponse.smart_collections  || []).map((c) => ({ ...c, type: 'smart'  }));
const rawCollections    = [...customCollections, ...smartCollections];

// ── Build import summary ──────────────────────────────────────────────────
const activeProductCount  = rawProducts.filter((p) => p.status === 'active').length;
const skippedProductCount = rawProducts.length - activeProductCount;

const importSummary = {
  imported_at:           new Date().toISOString(),
  project_id:            projectId,
  shop_domain:           rawShopData.myshopify_domain || rawShopData.domain || '',
  product_count:         rawProducts.length,
  active_product_count:  activeProductCount,
  skipped_product_count: skippedProductCount,
  collection_count:      rawCollections.length,
  shopify_api_version:   runtimeConfig.shopify_api_version,
  import_errors:         [],
  pagination_note:       rawProducts.length === 250
    ? 'WARNING: exactly 250 products returned — store may have more. Pagination not implemented in Phase 12.'
    : null,
};

// ── Assemble shopify-import.json ─────────────────────────────────────────
const shopifyImport = {
  project_id:     projectId,
  raw_shop_data:  {
    shop_domain:      rawShopData.myshopify_domain || rawShopData.domain || '',
    shop_name:        rawShopData.name || '',
    shop_currency:    rawShopData.currency || '',
    shop_plan_name:   rawShopData.plan_name || '',
    shop_locale:      rawShopData.primary_locale || '',
    shop_country_code:rawShopData.country_code || '',
  },
  raw_products:       rawProducts,
  raw_collections:    rawCollections,
  import_summary:     importSummary,
};

// ── Atomic write ─────────────────────────────────────────────────────────
const projectDir  = path.join(projectRoot, projectId);
const finalPath   = path.join(projectDir, 'shopify-import.json');
const tmpPath     = path.join(projectDir, 'shopify-import.tmp.json');

fs.mkdirSync(projectDir, { recursive: true });
fs.writeFileSync(tmpPath, JSON.stringify(shopifyImport, null, 2), 'utf8');
fs.renameSync(tmpPath, finalPath);

// ── Update checkpoint ─────────────────────────────────────────────────────
const checkpointPath = path.join(projectRoot, projectId, '.runtime', 'checkpoint.json');
let checkpoint;
try {
  checkpoint = JSON.parse(fs.readFileSync(checkpointPath, 'utf8'));
} catch {
  // If checkpoint is missing, create a minimal one rather than halting
  checkpoint = {
    schema_version: '1.0', project_id: projectId,
    execution_run_id: 'run-unknown',
    chain_start_timestamp: new Date().toISOString(),
    last_updated_timestamp: new Date().toISOString(),
    chain_status: 'IN_PROGRESS', completed_workflows: [],
    failed_at: null, next_workflow: 'build-store-profile',
    review_gate_status: 'NOT_REACHED', review_gate_approved_at: null,
    env: runtimeConfig.env, llm_model_used: runtimeConfig.llm_model || null,
    shopify_api_version_used: runtimeConfig.shopify_api_version || null, notes: [],
  };
}

const now = new Date().toISOString();
checkpoint.completed_workflows.push({
  workflow_id:     'import-shopify-data',
  completed_at:    now,
  output_artifact: 'shopify-import.json',
  status:          'SUCCESS',
});
checkpoint.last_updated_timestamp = now;
checkpoint.next_workflow          = 'build-store-profile';

const cpTmp = checkpointPath + '.tmp';
fs.writeFileSync(cpTmp, JSON.stringify(checkpoint, null, 2), 'utf8');
fs.renameSync(cpTmp, checkpointPath);

// ── Append to execution log ───────────────────────────────────────────────
const logPath = path.join(projectRoot, projectId, '.runtime', 'execution-log.json');
try {
  const logData = fs.existsSync(logPath)
    ? JSON.parse(fs.readFileSync(logPath, 'utf8'))
    : { entries: [] };
  logData.entries.push({
    timestamp:        now,
    execution_run_id: checkpoint.execution_run_id,
    level:            'INFO',
    event_type:       'ARTIFACT_WRITE',
    workflow_id:      'import-shopify-data',
    artifact:         'shopify-import.json',
    message:          `shopify-import.json written. Products: ${activeProductCount} active, Collections: ${rawCollections.length}`,
  });
  if (importSummary.pagination_note) {
    logData.entries.push({
      timestamp: now, execution_run_id: checkpoint.execution_run_id,
      level: 'WARNING', event_type: 'ERROR',
      workflow_id: 'import-shopify-data',
      message: importSummary.pagination_note,
    });
  }
  const logTmp = logPath + '.tmp';
  fs.writeFileSync(logTmp, JSON.stringify(logData, null, 2), 'utf8');
  fs.renameSync(logTmp, logPath);
} catch { /* log write failure is non-fatal */ }

return [{
  json: {
    project_id:      projectId,
    artifact_path:   finalPath,
    artifact_name:   'shopify-import',
    import_summary:  importSummary,
    runtime_config:  runtimeConfig,
    status:          'SUCCESS',
  },
}];
